# Set operations in Python
A = {1, 2, 3, 4, 5}
B = {4, 5, 6, 7, 8}

union = A | B          # {1,2,3,4,5,6,7,8}
intersection = A & B   # {4, 5}
difference = A - B     # {1, 2, 3}
sym_diff = A ^ B       # {1, 2, 3, 6, 7, 8}

assert union == A | B
assert intersection == A & B
assert A.issubset(union)

# Power set
from itertools import combinations
def power_set(s):
    return {frozenset(c) for r in range(len(s)+1) for c in combinations(s, r)}

ps = power_set({1, 2, 3})
assert len(ps) == 2**3  # |P(A)| = 2^|A|

import numpy as np
from itertools import permutations

# Symmetric group S3 â€” all permutations of {0,1,2}
def compose_perm(p, q):
    """Compose two permutations: (pâˆ˜q)(i) = p(q(i))."""
    return tuple(p[q[i]] for i in range(len(p)))

S3 = list(permutations(range(3)))
assert len(S3) == 6  # |S3| = 3! = 6

# Verify group axioms
identity = (0, 1, 2)
assert identity in S3  # Identity exists

# Closure: composition of two permutations is a permutation
for p in S3:
    for q in S3:
        result = compose_perm(p, q)
        assert result in S3, f'Closure violated: {p} âˆ˜ {q} = {result}'

from collections import deque

def bfs(graph, start):
    """Breadth-First Search returning vertices in BFS order."""
    visited = {start}
    queue = deque([start])
    order = []
    while queue:
        vertex = queue.popleft()
        order.append(vertex)
        for neighbor in graph.get(vertex, []):
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)
    return order

def dfs(graph, start):
    """Depth-First Search (iterative) returning vertices in DFS order."""
    visited = set()
    stack = [start]
    order = []
    while stack:
        vertex = stack.pop()
        if vertex not in visited:
            visited.add(vertex)
            order.append(vertex)
            for neighbor in reversed(graph.get(vertex, [])):
                if neighbor not in visited:
                    stack.append(neighbor)
    return order

graph = {0: [1, 2], 1: [3], 2: [3], 3: []}
assert set(bfs(graph, 0)) == {0, 1, 2, 3}
assert set(dfs(graph, 0)) == {0, 1, 2, 3}

# ODD specification as structured data
odd_highway_l3 = {
    'name': 'Highway L3 Traffic Jam Pilot',
    'sae_level': 3,
    'roadway': {'type': 'highway', 'lanes': [2, 3, 4], 'divided': True},
    'speed_range': {'min_kmh': 0, 'max_kmh': 60},
    'environment': {
        'weather': ['clear', 'cloudy', 'light_rain'],
        'lighting': ['daylight', 'dusk'],
        'road_surface': ['dry', 'wet'],
    },
    'traffic': {'density': 'congested', 'participants': ['cars', 'trucks']},
    'connectivity': {'hd_map': True, 'v2x': False},
}

def is_within_odd(conditions, odd):
    """Check if current conditions fall within ODD boundaries."""
    if conditions['speed_kmh'] > odd['speed_range']['max_kmh']:
        return False
    if conditions['weather'] not in odd['environment']['weather']:
        return False
    return True

assert is_within_odd({'speed_kmh': 30, 'weather': 'clear'}, odd_highway_l3)
assert not is_within_odd({'speed_kmh': 130, 'weather': 'clear'}, odd_highway_l3)

# Logical scenario: cut-in from adjacent lane
logical_scenario_cut_in = {
    'name': 'Adjacent Vehicle Cut-in',
    'description': 'A vehicle in an adjacent lane changes into the ego lane ahead of the ego vehicle.',
    'parameters': {
        'ego_speed_kmh': {'min': 30, 'max': 130, 'distribution': 'uniform'},
        'relative_speed_kmh': {'min': -20, 'max': 20},
        'cut_in_distance_m': {'min': 5, 'max': 50},
        'cut_in_duration_s': {'min': 1.0, 'max': 5.0},
    },
    'pass_criteria': {
        'no_collision': True,
        'min_ttc_s': 1.5,
        'max_deceleration_ms2': 5.0,
    },
}

def generate_concrete_scenarios(logical, n=100):
    import random
    scenarios = []
    for _ in range(n):
        concrete = {}
        for param, spec in logical['parameters'].items():
            concrete[param] = random.uniform(spec['min'], spec['max'])
        scenarios.append(concrete)
    return scenarios

scenarios = generate_concrete_scenarios(logical_scenario_cut_in, n=1000)
assert len(scenarios) == 1000
assert all(30 <= s['ego_speed_kmh'] <= 130 for s in scenarios)

