# SOTIF 4-quadrant scenario classification
class SOTIFQuadrant:
    KNOWN_SAFE = 'known_safe'
    KNOWN_UNSAFE = 'known_unsafe'
    UNKNOWN_SAFE = 'unknown_safe'
    UNKNOWN_UNSAFE = 'unknown_unsafe'

def classify_scenario(scenario, known_triggers, mitigated_triggers):
    """Classify a scenario into the SOTIF 4-quadrant model."""
    trigger = scenario.get('triggering_condition')
    is_known = trigger in known_triggers
    is_mitigated = trigger in mitigated_triggers

    if is_known and is_mitigated:
        return SOTIFQuadrant.KNOWN_SAFE
    elif is_known and not is_mitigated:
        return SOTIFQuadrant.KNOWN_UNSAFE
    elif not is_known:
        # Unknown â€” we can't distinguish safe/unsafe until discovered
        return SOTIFQuadrant.UNKNOWN_UNSAFE  # Conservative assumption

known = {'rain_occlusion', 'sun_glare', 'tunnel_exit'}
mitigated = {'rain_occlusion', 'sun_glare'}

assert classify_scenario({'triggering_condition': 'rain_occlusion'}, known, mitigated) == 'known_safe'
assert classify_scenario({'triggering_condition': 'tunnel_exit'}, known, mitigated) == 'known_unsafe'
assert classify_scenario({'triggering_condition': 'novel_condition'}, known, mitigated) == 'unknown_unsafe'
